package main

import (
	"html/template"
	"net/http"
	"strings"
)

type Comment struct {
	Content string
}

var comments = []Comment{
	{Content: "This is a <b>bold</b> comment."},
	{Content: "Another comment with <i>italics</i>."},
}

func sanitize(input string) string {
	replacer := strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
		"\"", "&quot;",
		"'", "&#39;",
	)
	return replacer.Replace(input)
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	tmpl := `<html><body><h1>User Comments</h1><ul>{{range .}}<li>{{.Content}}</li>{{end}}</ul></body></html>`
	t, err := template.New("comments").Parse(tmpl)
	if err != nil {
		http.Error(w, "Error parsing template", http.StatusInternalServerError)
		return
	}

	sanitizedComments := make([]Comment, len(comments))
	for i, comment := range comments {
		sanitizedComments[i] = Comment{Content: sanitize(comment.Content)}
	}

	err = t.Execute(w, sanitizedComments)
	if err != nil {
		http.Error(w, "Error rendering template", http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}